def compute_score() -> tuple[str, float]:
    slide_number = 4
    before = next((s.image_path for s in original_ppt_screenshots if s.slide_number == slide_number), None)
    after = next((s.image_path for s in modified_ppt_screenshots if s.slide_number == slide_number), None)
    if not before or not after:
        return (f"Slide {slide_number} screenshot not found for before/after.", 0.5)
    prompt = (
        "You are shown the before and after images of a PowerPoint slide. "
        "Beyond the expected change of changing the French title text color from white to gold, "
        "are there any other changes on the slide? "
        "Start the answer with YES or NO. If NO, explain what you see."
    )
    result = vlm_call(prompt, images=[before, after], temperature=0.2, max_tokens=10)
    if 'no' in result.lower():
        return (f"No extraneous changes detected on slide {slide_number} beyond the French title text color change.", 1.0)
    else:
        return (f"Extraneous changes detected on slide {slide_number} beyond the French title text color change: {result}", 0.0)
